14.4 Reorient pucks

reorient_pucks &lt;- function(obj){
  obj@images$image@coordinates$x &lt;- obj$plot_x
  obj@images$image@coordinates$y &lt;- -obj$plot_y

  return(obj)
}

P102TA_17_RNA &lt;- reorient_pucks(P102TA_17_RNA)
P102TA_33_RNA &lt;- reorient_pucks(P102TA_33_RNA)
P108TA_32_RNA &lt;- reorient_pucks(P108TA_32_RNA)
